void solve(int CASE)
{
	ll n, m, q, V; cin >> n >> m >> q >> V;
	var p = vector<ll>();
	ll high = Math::log2(V);
	p.pb(V);
	fa(i, 1, 60) {
		if (i <= high) {
			if (!(V & (1ll << i))) {
				ll mask = (((1ll << (high + 1)) - 1) ^ ((1ll << (i + 1)) - 1));
				ll pre = mask & V | (1ll << i);
				p.pb(pre);
			}
		}
		else p.pb(1ll << i);
	}

	var s = Vec2<int>(n + 1, p.size());
	fa(i, 1, n)fa(j, 0, vs(p))s[i][j] = i;
	var find = [&](var find, int x, int y)->int {
		if (s[x][y] == x)return x;
		return s[x][y] = find(find, s[x][y], y);
		};
	fa(i, 1, m) {
		ll u, v, w; cin >> u >> v >> w;
		fa(j, 0, vs(p)) {
			int e1 = find(find, u, j);
			int e2 = find(find, v, j);
			if (e1 != e2 and (w & p[j]) == p[j])s[e2][j] = e1;
		}
	}

	while (q--) {
		int u, v; cin >> u >> v;
		bool ok = 0;
		fa(i, 0, vs(p)) {
			int e1 = find(find, u, i);
			int e2 = find(find, v, i);
			if (e1 == e2) {
				ok = 1;
				break;
			}
		}
		if (ok)cout << "Yes" << endl;
		else cout << "No" << endl;
	}
	return;
}
